INSERT INTO blog_posts (id, slug, cover_image_url, published_at, views_count, reading_time_minutes, status, created_at, updated_at) VALUES
('5293067d-f61f-4447-8dbb-9439265426bc', 'como-surgio-todo-esto', 'https://ik.imagekit.io/daranedag/perfil2.jpg?updatedAt=1761438263597', '2025-10-17T10:53:10.496363+00:00', 0, NULL, 'published', '2025-10-17T10:53:10.496363+00:00', '2025-10-26T00:25:00.771371+00:00'),
('c2d87cf2-8443-434f-af56-87a9cc92ffae', 'vida-profesional-y-otras-particularidades', 'https://ik.imagekit.io/daranedag/vida-profesional-y-otras-particularidades.png?updatedAt=1762382170875', '2025-11-05T22:37:22.164736+00:00', 0, NULL, 'published', '2025-11-05T22:37:22.164736+00:00', '2026-01-22T19:12:05.237144+00:00');
INSERT INTO blog_post_translations (id, post_id, language_code, title, excerpt, content, meta_description) VALUES
('9c7d3d13-0df1-431f-be84-8e2b4d4438ef', '5293067d-f61f-4447-8dbb-9439265426bc', 'es', 'Mi historia y tu bienvenida', 'Un relato honesto sobre cómo el autor transformó su sitio personal diegui.dev de una simple idea técnica en un proyecto con propósito, aprendizaje y valores.', '<p>No vengo a contarte <em>toda</em> mi historia, sino una parte de ella...</p><p>Si estás en esta sección de mi página, ya te diste cuenta de que es algo tipo personal/profesional, porque creo que esos ámbitos están relacionados. Hay más ámbitos individuales involucrados, que tal vez no notes que existen, pero se entrelazan con lo personal y, por ende, llegan a lo profesional. Tal vez hablemos de eso en otro post.</p><p>La verdad es que este sitio —<strong>diegui.dev</strong>— lleva bastante tiempo en marcha. Surgió como muchas otras ideas: queriendo ser una copia barata (<em>fruna-mercadona-las saladas</em>) de <strong>midu.dev</strong>. No en el sentido de los cursos ni del contenido que Midu comparte regularmente, sino en los aspectos estéticos y, sobre todo, en la estructura del código.</p><p>Pero cuando empecé a desarrollarla y tuve que definir colores, enlaces y demás en base a lo que tenía en mente… no me convenció del todo. Opté por dejarla en <em>stand-by</em>.</p><p>Sí, seguí pagando el dominio del sitio, y pasó todo un año lleno de trabajo, baile, música, aprendizaje y mayor claridad sobre lo que quería. Incluso renové el dominio, pudiendo haberlo dejado caducar.</p><p>Al principio, la página tenía estilos con <strong>TailwindCSS 4</strong>, una arquitectura con <strong>Vite + React</strong> y nada más.</p><p>Cuando empecé con el rediseño este año, pensé: <em>“Necesito una base de datos gratuita”</em>. No voy a gestionar usuarios (aún), así que no necesito una base que crezca a un ritmo exorbitante ni pagar por un servicio 24/7.</p><p>Por experiencias laborales —tema del siguiente post— se me ocurrió usar el <em>tier</em> gratuito de <strong>Render</strong> para la base de datos e ir migrándola cada 30 días (que es lo que dura lo gratis). Me agendé una hora de migración cada 29 días para no correr el último día con el temor de perder los datos.</p><p>Durante este último año me he estado asesorando bastante con la IA, y puedo contar que el diseño estructural del sitio nació de un <em>prompt</em> que puse en <strong>Stitch</strong> (sí, como <em>Lilo &amp; Stitch</em>, pero de Google).</p><p>No la conocía, pero es como un Figma con IA: le dices el estilo que quieres, te genera plantillas y opciones, puedes iterar los cambios, ¡y lo mejor es que te entrega el código! ❤️</p><p>Tomas todo —o solo la sección que te interesa— y luego la adaptas en tu editor. <em>Voilà</em>: diseño operativo.</p><p>No soy de las personas que copian y pegan sin saber qué están usando. Tengo mis resguardos cuando trabajo con IA: puedo copiar código y hacerlo funcionar, pero siempre me pregunto “¿y si deja de funcionar? ¿Dónde debo revisar?”. Por eso reviso siempre el código generado y hago mis propios ajustes.</p><p>Siguiendo con la arquitectura del sitio, le consulté al amigo ChatGPT por alternativas para crear mi sitio personal con blog, sabiendo que iba a necesitar una base de datos en la nube.</p><p>Entre las opciones que me dio, además de Render, estaba <strong>Supabase</strong>. No la conocía, pero era una alternativa recomendada y bien evaluada.</p><p>Le pedí a ChatGPT que me generara las tablas base para un blog y, cinco minutos después, tenía mi base en Supabase montada y andando. ¡Fue brutalmente épico!</p><p>Sentí que por fin tenía todos los medios para sacar el sitio adelante. Pensé: “¿Cómo no se me ocurrieron estas cosas hace un año?”.</p><p>Y ahí entendí: tal vez no era mi momento. Tal vez faltaban aprendizajes por sumar.</p><p>Como me gusta integrar lo que aprendo en mis proyectos, hace poco estuve viendo la <strong>Retool Summit</strong>.</p><p>(Si hubiera tenido los medios, quizás habría viajado a San Francisco para asistir).</p><p>Conocí las novedades del producto y las experiencias de grandes empresas como <strong>Colgate, Uber y Komatsu</strong>, y fue un gran <em>WOW</em>.</p><p>Además, incluyeron IA para generar aplicaciones. Probé algunas cosas: no todo me gustó, pero hubo una parte que sí… y es la que estoy usando ahora.</p><p>¿Para qué quería <strong>Retool</strong>?</p><p>Para tener un lugar donde administrar mis <em>posts</em> sin acceder directamente a la base de datos.</p><p>Un espacio para gestionar cada publicación, definir su idioma (idealmente que cada post exista también en inglés) y marcar si está en borrador o publicada.</p><p>Y ahí nació otra idea más… pero ya contaré más sobre eso ;)</p><p>Para cerrar este post, quiero reflexionar brevemente sobre los tiempos, el aprendizaje y las oportunidades:</p><p>Esto llevaba un año gestándose. Partió como una idea y terminó siendo otra.</p><p>En ese tiempo aprendí muchas cosas, surgieron nuevas herramientas y todo eso me ayudó a concretar el sitio.</p><p>De ahí nacieron también nuevas ideas, oportunidades de diseño y de venta, y la motivación de crear algo diferente, algo que se sostenga por sí mismo, porque la arquitectura lo permite.</p><p>No está hecho sobre palos de fósforos ni pegado con moco: toma lo mínimo necesario para crecer de forma orgánica, tal como dice el lema de la página:</p><p><strong>“Innovemos con código, colaboremos con honestidad.”</strong></p><p>Con esto quiero decir: inventemos lo que queramos y seamos transparentes al hacerlo.</p><p>No busco aprovecharme de una necesidad, y espero que nadie se aproveche de mi honestidad. <strong>Valores.</strong></p><p>Nos vemos en el próximo post… que se viene con salseito 😏</p>', 'Descubre cómo nació y evolucionó diegui.dev, un sitio donde desarrollo, aprendizaje e innovación se unen con honestidad. Reflexión sobre construir con propósito y dejar que las ideas maduren a su tiempo.'),
('bbf67f59-59d5-427a-b8ab-b2b4701df71d', 'c2d87cf2-8443-434f-af56-87a9cc92ffae', 'es', 'La vida profesional y el día a día', 'Algunas ideas sobre la vida profesional y como el día a día ayuda o no', '<p>Para este segundo post, tengo muchisimas ideas en mente, probablemente terminen siendo más de un post. El tema es que también se requiere tiempo para poder escribir /redactar y editar para que sea todo comprensible.</p><p><br></p><p>Con todo quiero continuar diciendo que cuando se empieza a trabajar, no solo en lo profesional, porque puede ser hasta un oficio, creo que uno lo hace buscando un "algo". Por ahora lo llamaremos "algo". Con este algo en mente, me lanzo a la vida, pensando que ese algo es lo que necesito para lograr mis objetivos en la vida. Tal vez, ese algo comienza como algo importante: "Consegui mi primer trabajo y voy a poder juntar dinero para comprar N cosas, ahorrar para cosas más grandes e importantes".</p><p>Pero junto con toda esta ilusión, magia o como quieras llamarlo, también vienen las desilusiones, vienen dificultades y situaciones inesperadas que muchas veces están fuera de nuestro control:</p><p>A la empresa donde trabajas le va bien, cada vez mejor y de pronto la venden y empiezan a mover gente y toca estar entre esa gente. Tal vez no por "mal" ingeniero en mi caso. Pero con poca claridad de por qué se dieron las situaciones así.</p><p>Decía que viene la desilusión porque pensaba que en este primer trabajo estaba el "algo" que quería para mi proyecto de vida.</p><p>Pero no fue así y por ende tocó replantearse la vida: ¿Qué hago cuando me despiden? ¿Cómo vivo? ¿Cuanto tiempo puedo vivir y/o mantener mi estilo de vida? ¿Cómo están mis finanzas? ¿Qué tramites debo hacer? ¿Cuánto tiempo debe pasar para buscar un nuevo trabajo? ¿Hay gente que dependa de mí y mi sueldo? ¿Trabajo en lo mismo? ¿Es mi momento de emprender o ser independiente o freelance?</p><p><br></p><p>Y obviamente en el momento, yo me angustié, llamé a amigos/familia para decirles "Oye, me echaron" y luego las preguntas de vuelta: "pero cómo?", "qué vas a hacer?", "te pagaron todo?" y las frases: "tranquil@, todo cambio es para mejor", "no saben lo que se pierden", "tomate unos dias de descanso y luego sales a buscar trabajo de nuevo" y tal vez los más proactivos dirán "linkedin perro", dependiendo el área get on board, fiverr, etc.</p><p><br></p><p>Una vez pasadas todas estas preguntas, frases, ideas, dormir, descansar y de alguna manera sentir que estas de "vacaciones forzadas". Voy a actualizar mi CV!!</p><p>Estará bien mi CV? Es atractivo? Soy deseable para las empresas? Logrará este CV destacar frente a decenas, cientos o miles de CV que podrían postular a un cargo??</p><p>Me podré asesorar?? (ojalá gratis porque no genero dinero en estos momentos ó no me puedo permitir pagarle esa cantidad a un asesor)</p><p>Postulo a un cargo y la bendita espera se hace notar...</p><p>... pasan los días</p><p>... cargas y re cargas tu correo...</p><p>... te aseguras que todas las notificaciones en el teléfono estén activas ...</p><p>... te aseguras que el telefono esté con el sonido al máximo porque si suena por notificación o llamada ... estar muy atento para responder</p><p>Y postulo a otra oferta, luego a otra... otra... otra...</p><p>Me desanimo porque nadie responde... me enojo porque digo, "soy buen profesional, mejor que aquel y que ese está ahí"... veo alguna noticia y digo "yo seguro trabajo mejor"</p><p>Pero no llaman, no escriben, no responden...</p><p>Estará bien mi enfoque??</p><p>Han pasado 2 semanas de descanso y ya voy 1 semana que envío CVs, postulaciones a trabajos en lo que sea y no hay respuesta.</p><p>Entro todos los días a todas las plataformas a revisar si hay una nueva oferta porque el influencer del trabajo dijo que hay que ser de los primeros postulantes para aumentar las posibilidades de que vean tu CV y te puedan llamar si calzas con el perfil.</p><p><br></p><p>Pero aún así, no pasa nada más que el tiempo y pasan 1 mes, 2 meses...y me pregunto ¿qué tengo de malo que no llamo la atención?</p><p>¿qué estoy haciendo mal? y empieza la desesperación... me alcanza para el arriendo, comida y gastos basicos por otro mes?</p><p>me tengo que endeudar con la tarjeta de credito? con la linea de credito?</p><p>le pido plata a alguien de confianza? o a alguien de dudosa confianza?</p><p><br></p><p>Y de repente, un correo: "vimos tu cv y nos gustó tu perfil, creemos que calzas con lo que estamos buscando, cuando tienes tiempo para una entrevista?"</p><p>La gloria, una oportunidad... y ya te ves trabajando en esa empresa.</p><p>Cómo me preparo para la entrevista?</p><p>Quien me entrevista?</p><p>Qué empresa es?</p><p>tal vez muy bajito en el subconsciente se empiece a formular una pregunta: "quiero trabajar para esta empresa?", "soy animalista empedernido y me estan llamando de una cosmética que prueba todos sus productos en animales, puedo trabajar ahí?" "tengo principios o valores que no voy transgredir aun asi me muera de hambre yo y quien dependa de mi?"</p><p>"que quiero hacer con mi vida profesional?"</p><p>"puedo vender mis principios y valores por un tiempo para poder sobrevivir?"</p><p>"me están ofreciendo menos del valor de mercado? lo justo? o muchisimo más?"</p><p><br></p><p>Y aparecen más ofertas y más postulaciones enviadas y de pronto empiezan a llover correos y llamadas, entrevistas iniciales, pruebas tecnicas... "me la puedo?", "digo que no?", "termino este proceso aqui no más?", "la prueba técnica estaba dificil y no logré resolverla", "los algoritmos que me preguntaron, brigidos", "lo habré hecho bien?"</p><p>Llega otro momento donde te contactan para empezar procesos y ni te acuerdas qué empresa era, qué cargo era...</p><p>Tampoco sabes si aceptar iniciar otro proceso de entrevistas más, porque no tienes respuesta aún de los otros procesos que ya empezaste... incertidumbre...</p><p><br></p><p>Hasta que empiezan a llegar, de manera algo responsable, los correos diciendote: "gracias por tu interés en el cargo con nosotros, pero continuaremos este proceso de selección sin tu postulación" y no hay más feedback que ese.</p><p>¿qué pasó, si era el idoneo para el cargo? ¿tan mal hice la prueba? ¿me habrán encontrado demasiado pitiado en la entrevista psicolaboral?</p>', '');
